  /** Sort by issue due date */
  dueDate?: DueDateSort | null | undefined;
  /** Sort by estimate */
  estimate?: EstimateSort | null | undefined;
  /** Sort by label */
  label?: LabelSort | null | undefined;
  /** Sort by label group */
  labelGroup?: LabelGroupSort | null | undefined;
  /** [ALPHA] Sort by number of links associated with the issue */
  linkCount?: LinkCountSort | null | undefined;
  /** Sort by manual order */
  manual?: ManualSort | null | undefined;
  /** Sort by Project Milestone target date */
  milestone?: MilestoneSort | null | undefined;
  /** Sort by priority */
  priority?: PrioritySort | null | undefined;
  /** Sort by Project name */
  project?: ProjectSort | null | undefined;
  /** [ALPHA] Sort by most recent release date */
  release?: ReleaseSort | null | undefined;
